+        }
+        return AttemptOutcome::Terminal(err);
+    }
+
+    let text = match resp.text().await {
+        Ok(t) => t,
+        Err(e) => return AttemptOutcome::Terminal(NetlifyError::Http(e)),
+    };
+
+    match serde_json::from_str::<Vec<T>>(&text) {
+        Ok(v) => AttemptOutcome::Success(v),
+        Err(e) => {
