+#[derive(Debug, Clone, Serialize)]
+pub struct DoctorResult {
+    pub ready: bool,
+    pub status: DoctorStatus,
+    pub checks: Vec<DoctorCheck>,
+    #[serde(skip_serializing_if = "Option::is_none")]
+    provisioning: Option<ProvisioningReadiness>,
+}
