+    #[test]
+    fn json_error_is_not_retryable() {
+        let raw_err = serde_json::from_str::<serde_json::Value>("not json").unwrap_err();
+        let err = NetlifyError::Json(raw_err);
+        assert!(!err.is_retryable());
