+        if let Some(config) = &self.config {
+            checks.push(DoctorCheck {
+                name: "environment".into(),
+                passed: true,
+                message: Some(if config.sandbox {
+                    "PayPal sandbox mode".into()
+                } else {
+                    "PayPal production mode".into()
