+#[async_trait]
+impl FcpConnector for PayPalConnector {
+    fn id(&self) -> &ConnectorId {
+        &self.base.id
+    }
+
+    async fn configure(&mut self, config: serde_json::Value) -> FcpResult<()> {
+        let cfg = PayPalConfig::from_value(config)?;
+        self.runtime = Some(ConnectorRuntime::new(
+            ConnectorRuntimeConfig::default()
+                .with_request_timeout(Duration::from_millis(cfg.request_timeout_ms)),
+        ));
+        let client = PayPalClient::new(
+            &cfg.base_url,
+            cfg.client_id.clone(),
+            cfg.client_secret.clone(),
+            cfg.retry.clone(),
+        )
+        .await
+        .map_err(|e| FcpError::Internal {
+            message: format!("Client init: {e}"),
+        })?;
+        self.client = Some(client);
+        self.config = Some(cfg);
+        self.verifier = None;
+        self.base.set_configured(true);
+        self.base.set_handshaken(false);
+        info!(event = "paypal.configure", "Configured PayPal connector");
+        Ok(())
+    }
+
+    async fn handshake(&mut self, req: HandshakeRequest) -> FcpResult<HandshakeResponse> {
+        self.base.set_handshaken(true);
+        self.verifier = Some(CapabilityVerifier::new(
+            req.host_public_key,
+            req.zone.clone(),
+            self.base.instance_id.clone(),
+        ));
+        let caps = req
+            .capabilities_requested
+            .into_iter()
+            .map(|c| CapabilityGrant {
+                capability: c,
+                operation: None,
+            })
+            .collect();
+        Ok(HandshakeResponse {
+            status: "accepted".into(),
+            capabilities_granted: caps,
+            session_id: SessionId::new(),
+            manifest_hash: Self::manifest_hash(),
+            nonce: req.nonce,
+            event_caps: Some(EventCaps {
+                streaming: false,
+                replay: false,
+                min_buffer_events: 0,
+                requires_ack: false,
+            }),
+            auth_caps: None,
+            op_catalog_hash: None,
+        })
+    }
+
+    async fn health(&self) -> HealthSnapshot {
+        let mut snap = if self.config.is_some() {
+            HealthSnapshot::ready()
+        } else {
+            HealthSnapshot::degraded("not configured")
+        };
+        snap.uptime_ms = u64::try_from(self.started_at.elapsed().as_millis()).unwrap_or(u64::MAX);
+        snap.details = Some(json!({
+            "configured": self.config.is_some(),
+            "handshaken": self.base.handshaken.load(Ordering::Acquire),
+            "sandbox": self.config.as_ref().map(|c| c.sandbox).unwrap_or(false),
+            "manifest_hash": Self::manifest_hash(),
+        }));
+        snap
+    }
+
+    async fn self_check(&self) -> FcpResult<SelfCheckReport> {
+        let Some(_config) = &self.config else {
+            return Ok(SelfCheckReport::degraded(
+                "not_configured",
+                "Connector is not configured",
+            ));
+        };
+
+        let Some(client) = &self.client else {
+            return Ok(SelfCheckReport::failed(
+                "client_missing",
+                "PayPal HTTP client not initialized; re-run configure",
+            ));
+        };
+        let Some(runtime) = &self.runtime else {
+            return Ok(SelfCheckReport::failed(
+                "runtime_missing",
+                "ConnectorRuntime not initialized; re-run configure",
+            ));
+        };
+
+        match client.health_check(runtime).await {
+            Ok(true) => {
+                info!(event = "paypal.self_check", "PayPal self_check passed");
+                Ok(SelfCheckReport::ok())
+            }
+            Ok(false) => Ok(SelfCheckReport::degraded(
+                "api_degraded",
+                "PayPal API returned server error",
+            )),
+            Err(error) if error.is_retryable() => Ok(SelfCheckReport::degraded(
+                "self_check_retryable",
+                error.to_string(),
+            )),
+            Err(error) => Ok(SelfCheckReport::failed(
+                "self_check_failed",
+                error.to_string(),
+            )),
+        }
+    }
+
+    async fn simulate(&self, req: SimulateRequest) -> FcpResult<SimulateResponse> {
+        Ok(SimulateResponse::allowed(req.id))
+    }
+
+    fn metrics(&self) -> ConnectorMetrics {
+        self.base.metrics()
+    }
+
+    async fn shutdown(&mut self, _req: ShutdownRequest) -> FcpResult<()> {
+        if let Some(runtime) = &self.runtime {
+            runtime.shutdown();
+        }
+        self.runtime = None;
+        self.client = None;
+        self.config = None;
+        self.verifier = None;
+        self.base.set_configured(false);
+        self.base.set_handshaken(false);
+        Ok(())
+    }
+
+    fn introspect(&self) -> Introspection {
+        Introspection {
+            operations: operations_info(),
+            events: Vec::new(),
+            resource_types: Vec::new(),
+            auth_caps: None,
+            event_caps: Some(EventCaps {
+                streaming: false,
+                replay: false,
+                min_buffer_events: 0,
+                requires_ack: false,
+            }),
+        }
+    }
+
+    async fn invoke(&self, req: InvokeRequest) -> FcpResult<InvokeResponse> {
+        let result = self.invoke_inner(req).await;
+        self.base.record_request(result.is_ok());
+        result
+    }
+
+    async fn subscribe(&self, _req: SubscribeRequest) -> FcpResult<SubscribeResponse> {
+        Err(FcpError::StreamingNotSupported)
+    }
+    async fn unsubscribe(&self, _req: UnsubscribeRequest) -> FcpResult<()> {
+        Err(FcpError::StreamingNotSupported)
+    }
+}
